	// Run go mod tidy to clean up
	if err := runGoCommand([]string{"mod", "tidy"}, env); err != nil {
		return fmt.Errorf("go mod tidy failed: %w", err)
	}

	// Verify the final go.sum for consistency
	if err := verifyGoSum(); err != nil {
		log.Printf("WARNING: go.sum verification note: %v", err)
	}

	return nil
