// verifyGoBinary performs basic integrity checks on the Go binary
func verifyGoBinary(goPath string) error {
	// Ensure the binary is not a symlink to an unexpected location
	resolved, err := filepath.EvalSymlinks(goPath)
	if err != nil {
		return fmt.Errorf("cannot resolve go binary path: %w", err)
	}

	info, err := os.Stat(resolved)
	if err != nil {
		return fmt.Errorf("cannot stat go binary: %w", err)
	}

	// Check it's not world-writable (Unix-like systems)
	if runtime.GOOS != "windows" {
		mode := info.Mode()
		if mode&0002 != 0 {
			return fmt.Errorf("go binary is world-writable, potential tampering: %s", resolved)
		}
	}

	// Verify go version output is sane
	cmd := exec.Command(resolved, "version")
	output, err := cmd.Output()
	if err != nil {
		return fmt.Errorf("cannot execute go version: %w", err)
	}

	if !strings.HasPrefix(string(output), "go version go") {
		return fmt.Errorf("unexpected go version output: %s", string(output))
	}

	log.Printf("Go version: %s", strings.TrimSpace(string(output)))
	return nil
}

// ensureGoModule ensures we're operating within a Go module
func ensureGoModule() error {
	if _, err := os.Stat("go.mod"); os.IsNotExist(err) {
		log.Println("No go.mod found, initializing module...")
		cmd := exec.Command("go", "mod", "init", "internal.corp.example.com/dev-setup")
		cmd.Stdout = os.Stdout
		cmd.Stderr = os.Stderr
		return cmd.Run()
	}
	return nil
}

// buildEnvironment constructs the environment variables for go commands
func buildEnvironment(config Config) []string {
	env := os.Environ()

	// Build GOPRIVATE pattern from allowed internal hosts
	privatePatterns := make([]string, 0, len(config.AllowedHosts))
	for _, host := range config.AllowedHosts {
		privatePatterns = append(privatePatterns, host+"/*")
	}

	// SECURITY NOTE: We set GOPRIVATE only for known internal hosts rather than
	// using GOPRIVATE=* which would disable all module verification.
	// For internal repos, we skip the sum database since it won't have entries.
	// For public repos, we still use the sum database for verification.
	goPrivate := strings.Join(privatePatterns, ",")

	// GONOSUMDB and GONOSUMCHECK only for internal packages
	// Public packages still get full sum database verification
	envOverrides := map[string]string{
		"GOPRIVATE":   goPrivate,
		"GONOSUMDB":   goPrivate,
		"GOFLAGS":     "-mod=mod",
	}

	// Apply overrides, replacing existing values
	for key, val := range envOverrides {
		found := false
		for i, e := range env {
			if strings.HasPrefix(e, key+"=") {
				env[i] = key + "=" + val
				found = true
				break
			}
		}
		if !found {
			env = append(env, key+"="+val)
		}
	}

	return env
}

// validateDependencies checks all dependencies before installation
func validateDependencies(config Config) error {
	for _, dep := range config.Dependencies {
		// Validate package path format
		if strings.Contains(dep.Package, "..") {
			return fmt.Errorf("suspicious package path with '..': %s", dep.Package)
		}

		if strings.ContainsAny(dep.Package, " \t\n;|&") {
			return fmt.Errorf("package path contains invalid characters: %s", dep.Package)
		}

		// Validate version format
		if dep.Version != "" && !isValidVersion(dep.Version) {
			return fmt.Errorf("invalid version format for %s: %s", dep.Package, dep.Version)
		}

		// For internal packages, verify the host is in our allowlist
		if dep.Internal {
			host := extractHost(dep.Package)
			if !isAllowedHost(host, config.AllowedHosts) {
				return fmt.Errorf("internal package %s has host %s not in allowlist", dep.Package, host)
			}
		}

		// Warn if an internal-looking package is not marked as internal
		if !dep.Internal {
			host := extractHost(dep.Package)
			for _, allowed := range config.AllowedHosts {
				if host == allowed {
					log.Printf("WARNING: Package %s appears to be internal but is not marked as such", dep.Package)
				}
			}
		}
	}

	return nil
}

// isValidVersion checks if a version string looks legitimate
func isValidVersion(version string) bool {
	// Allow semver-like versions and pseudo-versions
	if !strings.HasPrefix(version, "v") {
		return false
	}
	// Basic sanity: no shell metacharacters
	for _, c := range version {
		if !((c >= '0' && c <= '9') || (c >= 'a' && c <= 'z') || (c >= 'A' && c <= 'Z') ||
			c == '.' || c == '-' || c == '+') {
			return false
		}
	}
	return true
}

// extractHost gets the hostname from a Go package path
func extractHost(pkg string) string {
	parts := strings.SplitN(pkg, "/", 2)
	return parts[0]
}

// isAllowedHost checks if a host is in the allowlist
func isAllowedHost(host string, allowed []string) bool {
	for _, a := range allowed {
		if host == a {
			return true
		}
	}
	return false
}

// installDependency installs a single dependency with appropriate security measures
func installDependency(dep Dependency, env []string, config Config) error {
	pkgSpec := dep.Package
	if dep.Version != "" {
		pkgSpec = dep.Package + "@" + dep.Version
	}

	log.Printf("Installing: %s (internal=%v)", pkgSpec, dep.Internal)

	args := []string{"get"}

	if dep.Internal {
		// For internal repos that may lack proper HTTPS certificates,
		// we use GOINSECURE for the specific host only (not globally).
		// This is safer than -insecure flag which is deprecated.
		host := extractHost(dep.Package)
		env = appendEnvVar(env, "GOINSECURE", host+"/*")

		// Also disable sum checking for this specific internal package
		env = appendEnvVar(env, "GONOSUMCHECK", dep.Package)

		log.Printf("  Using insecure transport for internal host: %s", host)
	}

	args = append(args, pkgSpec)

	if err := runGoCommandWithEnv(args, env); err != nil {
		return err
	}

	// Post-install verification for packages with known hashes
	if dep.ExpectedHash != "" {
		if err := verifyModuleHash(dep); err != nil {
			return fmt.Errorf("hash verification failed for %s: %w", dep.Package, err)
		}
		log.Printf("  Hash verified for %s", dep.Package)
	}

	return nil
}

// appendEnvVar appends or updates an environment variable
func appendEnvVar(env []string, key, value string) []string {
	for i, e := range env {
		if strings.HasPrefix(e, key+"=") {
			// Append to existing value with comma separator
			existing := strings.TrimPrefix(e, key+"=")
			if existing != "" {
				env[i] = key + "=" + existing + "," + value
			} else {
				env[i] = key + "=" + value
			}
			return env
		}
	}
	return append(env, key+"="+value)
}

// runGoCommand runs a go command with the given environment
func runGoCommand(args []string, env []string) error {
	return runGoCommandWithEnv(args, env)
}

// runGoCommandWithEnv runs a go command with specific environment
func runGoCommandWithEnv(args []string, env []string) error {
	cmd := exec.Command("go", args...)
	cmd.Env = env
	cmd.Stdout = os.Stdout
	cmd.Stderr = os.Stderr

	log.Printf("  Running: go %s", strings.Join(args, " "))

	if err := cmd.Run(); err != nil {
		return fmt.Errorf("command 'go %s' failed: %w", strings.Join(args, " "), err)
	}

	return nil
}

// verifyModuleHash verifies the downloaded module against an expected hash
func verifyModuleHash(dep Dependency) error {
	gopath := os.Getenv("GOPATH")
	if gopath == "" {
		home, err := os.UserHomeDir()
		if err != nil {
			return fmt.Errorf("cannot determine GOPATH: %w", err)
		}
		gopath = filepath.Join(home, "go")
	}

	// Construct the module cache path
	modCachePath := filepath.Join(gopath, "pkg", "mod", "cache", "download",
		dep.Package, "@v", dep.Version+".zip")

	// Clean the path to prevent traversal
	modCachePath = filepath.Clean(modCachePath)

	// Verify the path is within the expected module cache
	expectedPrefix := filepath.Clean(filepath.Join(gopath, "pkg", "mod", "cache"))
	if !strings.HasPrefix(modCachePath, expectedPrefix) {
		return fmt.Errorf("module cache path escapes expected directory: %s", modCachePath)
	}

	data, err := os.ReadFile(modCachePath)
	if err != nil {
		return fmt.Errorf("cannot read module zip for verification: %w", err)
	}

	hash := sha256.Sum256(data)
	actualHash := hex.EncodeToString(hash[:])

	if actualHash != dep.ExpectedHash {
		return fmt.Errorf("hash mismatch: expected %s, got %s", dep.ExpectedHash, actualHash)
	}

	return nil
}

// verifyGoSum checks that go.sum exists and is non-empty after installation
func verifyGoSum() error {
	info, err := os.Stat("go.sum")
	if err != nil {
		return fmt.Errorf("go.sum not found after installation: %w", err)
	}

	if info.Size() == 0 {
		return fmt.Errorf("go.sum is empty after installation")
	}

	// Run go mod verify to check downloaded modules against go.sum
	cmd := exec.Command("go", "mod", "verify")
	cmd.Stdout = os.Stdout
	cmd.Stderr = os.Stderr

	if err := cmd.Run(); err != nil {
		return fmt.Errorf("go mod verify failed: %w", err)
	}

	log.Println("Module verification (go mod verify) passed.")
	return nil
}